PROGRAM TankLevelMonitor
VAR_INPUT
  RawLevel : INT;
  HighAlarmSP : REAL;
  LowAlarmSP : REAL;
  Hysteresis : REAL;
END_VAR
VAR_OUTPUT
  LevelPct : REAL;
  HighAlarm : BOOL;
  LowAlarm : BOOL;
END_VAR
VAR_TEMP
  HighThr : REAL;
  LowThr : REAL;
END_VAR

LevelPct := INT_TO_REAL(RawLevel) / 276.48;
HighThr := HighAlarmSP - Hysteresis;
LowThr := LowAlarmSP + Hysteresis;

IF LevelPct >= HighAlarmSP THEN
  HighAlarm := TRUE;
ELSIF LevelPct < HighThr THEN
  HighAlarm := FALSE;
END_IF;

IF LevelPct <= LowAlarmSP THEN
  LowAlarm := TRUE;
ELSIF LevelPct > LowThr THEN
  LowAlarm := FALSE;
END_IF;

END_PROGRAM

PROGRAM MotorStarDelta
VAR_INPUT
    Start_btn: BOOL;
    Stop_btn: BOOL;
    Overload: BOOL;
END_VAR
VAR_OUTPUT
    Main_Contactor: BOOL;
    Star_Contactor: BOOL;
    Delta_Contactor: BOOL;
    Fault: BOOL;
END_VAR
VAR
    startEdge: R_TRIG;
    starTimer: TON;
    state: INT := 0;
END_VAR

startEdge(CLK := Start_btn);
starTimer(IN := state = 1, PT := T#3s);
Fault := Overload;

IF Stop_btn OR Overload THEN
    state := 0;
    Main_Contactor := FALSE;
    Star_Contactor := FALSE;
    Delta_Contactor := FALSE;
ELSE
    CASE state OF
        0:
            IF startEdge.Q THEN
                state := 1;
            END_IF;
        1:
            Main_Contactor := TRUE;
            Star_Contactor := TRUE;
            Delta_Contactor := FALSE;
            IF starTimer.Q THEN
                state := 2;
            END_IF;
        2:
            Main_Contactor := TRUE;
            Star_Contactor := FALSE;
            Delta_Contactor := TRUE;
    END_CASE;
END_IF;

END_PROGRAM

TYPE
    ConveyorState: (ST_IDLE, ST_RUNNING, ST_REJECTING, ST_FAULT);
END_TYPE

PROGRAM SortingConveyor
VAR_INPUT
    startCmd: BOOL;
    sensorPresent: BOOL;
    sensorDefect: BOOL;
    eStop: BOOL;
END_VAR

VAR_OUTPUT
    motorRun: BOOL;
    rejectSolenoid: BOOL;
END_VAR

VAR
    state: ConveyorState := ST_IDLE;
    rejectTimer: TON;
END_VAR

(* Fault handling has highest priority *)
IF eStop THEN
    state := ST_FAULT;
ELSE
    CASE state OF
        ST_IDLE:
            IF startCmd THEN
                state := ST_RUNNING;
            END_IF;
        ST_RUNNING:
            IF sensorPresent AND sensorDefect THEN
                state := ST_REJECTING;
            END_IF;
        ST_REJECTING:
            IF rejectTimer.Q THEN
                state := ST_RUNNING;
            END_IF;
        ST_FAULT:
            IF NOT eStop THEN
                state := ST_IDLE;
            END_IF;
    END_CASE;
END_IF;

(* Timer control *)
IF state = ST_REJECTING THEN
    rejectTimer(IN := TRUE, PT := T#500ms);
ELSE
    rejectTimer(IN := FALSE);
END_IF;

(* Outputs *)
motorRun := (state = ST_RUNNING);
rejectSolenoid := (state = ST_REJECTING);
END_PROGRAM

FUNCTION_BLOCK PID_Temperature
VAR_INPUT
    Enable : BOOL;
    Setpoint : REAL;
    ProcessValue : REAL;
    Kp : REAL := 2.0;
    Ki : REAL := 0.05;
    Kd : REAL := 0.0;
    CycleTime : TIME := T#100ms;
END_VAR
VAR_OUTPUT
    Output : REAL;
END_VAR
VAR
    Integrator : REAL;
    PrevError : REAL;
END_VAR
VAR
    Ts : REAL;
    Error : REAL;
    P : REAL;
    I : REAL;
    D : REAL;
END_VAR

IF NOT Enable THEN
    Output := 0.0;
    Integrator := 0.0;
    PrevError := 0.0;
ELSE
    Ts := TIME_TO_REAL(CycleTime);
    Error := Setpoint - ProcessValue;
    P := Kp * Error;
    Integrator := Integrator + Ki * Error * Ts;
    I := Integrator;
    IF Ts > 0.0 THEN
        D := Kd * (Error - PrevError) / Ts;
    ELSE
        D := 0.0;
    END_IF;
    Output := P + I + D;
    IF Output < 0.0 THEN
        Output := 0.0;
    ELSIF Output > 100.0 THEN
        Output := 100.0;
    END_IF;
    PrevError := Error;
END_IF;
END_FUNCTION_BLOCK

PROGRAM PumpLeadLag
VAR_INPUT
    LevelLow : BOOL;
    LevelHigh : BOOL;
    Pump1Fault : BOOL;
    Pump2Fault : BOOL;
    ManualMode : BOOL;
    ManualP1Run : BOOL;
    ManualP2Run : BOOL;
END_VAR

VAR_OUTPUT
    P1Run : BOOL;
    P2Run : BOOL;
END_VAR

VAR
    leadPump : INT := 1;
END_VAR

IF ManualMode THEN
    P1Run := ManualP1Run;
    P2Run := ManualP2Run;
ELSE
    (* Fault handling in auto mode *)
    IF leadPump = 1 AND Pump1Fault THEN
        leadPump := 2;
    ELSIF leadPump = 2 AND Pump2Fault THEN
        leadPump := 1;
    END_IF;

    IF LevelHigh THEN
        P1Run := FALSE;
        P2Run := FALSE;
    ELSIF LevelLow THEN
        IF leadPump = 1 THEN
            P1Run := TRUE;
            P2Run := FALSE;
        ELSE
            P1Run := FALSE;
            P2Run := TRUE;
        END_IF;
    ELSE
        P1Run := FALSE;
        P2Run := FALSE;
    END_IF;
END_IF;

END_PROGRAM

PROGRAM BatchDoseSequence
VAR_INPUT
  StartSeq : BOOL;
  Abort : BOOL;
END_VAR
VAR_OUTPUT
  Valve1 : BOOL;
  Valve2 : BOOL;
  Valve3 : BOOL;
  SeqDone : BOOL;
  SeqActive : BOOL;
END_VAR
VAR
  Step : INT;
  Tmr1 : TON;
  Tmr2 : TON;
  Tmr3 : TON;
END_VAR

IF Abort THEN
  Step := 0;
  Valve1 := FALSE;
  Valve2 := FALSE;
  Valve3 := FALSE;
  SeqDone := FALSE;
  SeqActive := FALSE;
  Tmr1(IN := FALSE, PT := T#0s);
  Tmr2(IN := FALSE, PT := T#0s);
  Tmr3(IN := FALSE, PT := T#0s);
ELSE
  CASE Step OF
    0:
      Valve1 := FALSE;
      Valve2 := FALSE;
      Valve3 := FALSE;
      SeqDone := FALSE;
      SeqActive := FALSE;
      Tmr1(IN := FALSE, PT := T#0s);
      Tmr2(IN := FALSE, PT := T#0s);
      Tmr3(IN := FALSE, PT := T#0s);
      IF StartSeq THEN
        Step := 1;
      END_IF;
    1:
      Valve1 := TRUE;
      Valve2 := FALSE;
      Valve3 := FALSE;
      SeqDone := FALSE;
      SeqActive := TRUE;
      Tmr1(IN := TRUE, PT := T#2s);
      IF Tmr1.Q THEN
        Step := 2;
      END_IF;
    2:
      Valve1 := FALSE;
      Valve2 := TRUE;
      Valve3 := FALSE;
      SeqDone := FALSE;
      SeqActive := TRUE;
      Tmr2(IN := TRUE, PT := T#3s);
      IF Tmr2.Q THEN
        Step := 3;
      END_IF;
    3:
      Valve1 := FALSE;
      Valve2 := FALSE;
      Valve3 := TRUE;
      SeqDone := FALSE;
      SeqActive := TRUE;
      Tmr3(IN := TRUE, PT := T#1s);
      IF Tmr3.Q THEN
        Step := 4;
      END_IF;
    4:
      Valve1 := FALSE;
      Valve2 := FALSE;
      Valve3 := FALSE;
      SeqDone := TRUE;
      SeqActive := FALSE;
      Tmr1(IN := FALSE, PT := T#0s);
      Tmr2(IN := FALSE, PT := T#0s);
      Tmr3(IN := FALSE, PT := T#0s);
    ELSE
      Step := 0;
  END_CASE;
END_IF;

END_PROGRAM

PROGRAM SafetyInterlock
VAR_INPUT
    EStopOK : BOOL;
    GuardClosed : BOOL;
    ResetPB : BOOL;
END_VAR
VAR_OUTPUT
    MachineEnable : BOOL;
    SafetyFault : BOOL;
END_VAR
VAR
    resetTrigger : R_TRIG;
END_VAR

(* Обработка фронта кнопки сброса *)
resetTrigger(CLK := ResetPB);

(* Логика защёлки аварии *)
IF NOT EStopOK OR NOT GuardClosed THEN
    SafetyFault := TRUE;
ELSIF resetTrigger.Q AND EStopOK AND GuardClosed THEN
    SafetyFault := FALSE;
END_IF;

(* Включение машины только при отсутствии аварии и замкнутых цепях *)
MachineEnable := NOT SafetyFault AND EStopOK AND GuardClosed;

END_PROGRAM

PROGRAM ProductionCounter
VAR_INPUT
    productSensor : BOOL;
    resetBatch : BOOL;
    batchTarget : INT := 1000;
END_VAR
VAR_OUTPUT
    batchCount : INT;
    batchComplete : BOOL;
    totalCount : INT;
END_VAR
VAR
    sensorEdge : R_TRIG;
    counter : CTU;
END_VAR

sensorEdge(CLK := productSensor);
counter(CU := sensorEdge.Q, R := resetBatch, PV := batchTarget);

batchCount := counter.CV;
batchComplete := counter.Q;

IF sensorEdge.Q THEN
    totalCount := totalCount + 1;
END_IF;

END_PROGRAM

FUNCTION_BLOCK MovingAverageFilter
VAR_INPUT
  Enable : BOOL;
  RawInput : REAL;
  WindowSize : INT;
END_VAR
VAR_OUTPUT
  Filtered : REAL;
END_VAR
VAR
  buffer : ARRAY[0..9] OF REAL;
  head : INT;
  count : INT;
  sum : REAL;
  effectiveSize : INT;
END_VAR

(* Clamp WindowSize to 1..10 *)
IF WindowSize < 1 THEN
  effectiveSize := 1;
ELSIF WindowSize > 10 THEN
  effectiveSize := 10;
ELSE
  effectiveSize := WindowSize;
END_IF;

IF NOT Enable THEN
  (* Reset buffer *)
  count := 0;
  head := 0;
  sum := 0.0;
  Filtered := 0.0;
ELSE
  (* Add new value to circular buffer *)
  buffer[head] := RawInput;
  sum := sum + RawInput;

  IF count < effectiveSize THEN
    count := count + 1;
  ELSE
    (* Replace oldest value before overwriting *)
    sum := sum - buffer[head];
  END_IF;

  (* Move head pointer *)
  head := (head + 1) MOD 10;

  (* Calculate filtered value *)
  Filtered := sum / INT_TO_REAL(count);
END_IF;

END_FUNCTION_BLOCK
